ALGORITHM Diffie-Hellman-Key-Exchange
INPUT: None (uses hardcoded public parameters for demonstration)
OUTPUT: Shared secret key S that both parties agree on

// ============================================
// PUBLIC PARAMETERS (agreed upon by both parties)
// ============================================
FUNCTION Setup()
    p ← 23        // Large prime number (in practice: 2048 bits)
    g ← 5         // Primitive root modulo p (generator)
    RETURN (p, g)
END FUNCTION

// ============================================
// MODULAR EXPONENTIATION (g^e mod p)
// ============================================
FUNCTION ModExp(base, exponent, mod)
    result ← 1
    base ← base mod mod
    WHILE exponent > 0
        IF exponent mod 2 = 1 THEN
            result ← (result * base) mod mod
        END IF
        exponent ← exponent / 2
        base ← (base * base) mod mod
    END WHILE
    RETURN result
END FUNCTION

// ============================================
// ALICE'S SIDE (Initiator)
// ============================================
FUNCTION Alice-KeyGeneration(p, g)
    // Step 1: Alice generates private key
    a ← RandomInteger(1, p-2)    // Private key (kept secret)

    // Step 2: Alice computes public key
    A ← ModExp(g, a, p)          // Public key: A = g^a mod p

    RETURN (a, A)
END FUNCTION

FUNCTION Alice-ComputeSharedSecret(B, a, p)
    // Step 3: Alice computes shared secret
    S ← ModExp(B, a, p)          // S = B^a mod p = g^(b*a) mod p
    RETURN S
END FUNCTION

// ============================================
// BOB'S SIDE (Responder)
// ============================================
FUNCTION Bob-KeyGeneration(p, g)
    // Step 1: Bob generates private key
    b ← RandomInteger(1, p-2)    // Private key (kept secret)

    // Step 2: Bob computes public key
    B ← ModExp(g, b, p)          // Public key: B = g^b mod p

    RETURN (b, B)
END FUNCTION

FUNCTION Bob-ComputeSharedSecret(A, b, p)
    // Step 3: Bob computes shared secret
    S ← ModExp(A, b, p)          // S = A^b mod p = g^(a*b) mod p
    RETURN S
END FUNCTION

// ============================================
// MAIN PROTOCOL EXECUTION
// ============================================
FUNCTION Main()
    // Step 1: Get public parameters
    (p, g) ← Setup()

    // Step 2: Both parties generate their key pairs
    (a, A) ← Alice-KeyGeneration(p, g)
    (b, B) ← Bob-KeyGeneration(p, g)

    // Step 3: Exchange public keys (A and B sent over insecure channel)
    // In real scenario: Alice receives B, Bob receives A

    // Step 4: Both compute the same shared secret
    S_alice ← Alice-ComputeSharedSecret(B, a, p)
    S_bob ← Bob-ComputeSharedSecret(A, b, p)

    // Verification: Both should have the same secret
    IF S_alice = S_bob THEN
        PRINT "Key exchange successful!"
        PRINT "Shared Secret S =", S_alice
    ELSE
        PRINT "Key exchange failed!"
    END IF

    RETURN S_alice
END FUNCTION

// ============================================
// EVE'S ATTACK (Demonstrating DLP difficulty)
// ============================================
FUNCTION Eve-Attempt(p, g, A, B)
    // Eve sees: p, g, A, B
    // To find S, Eve needs either a or b
    // a = discrete_log(g, A, p)  // Computationally infeasible for large p
    // S = B^a mod p
    PRINT "Eve cannot compute shared secret without solving DLP"
END FUNCTION

#include <stdio.h>
#include <stdlib.h>
#include <time.h>

/*
 * Diffie-Hellman Key Exchange Implementation in C
 * Educational demonstration with small numbers
 * In practice, use 2048-bit or larger primes
 */

/*
 * Fast Modular Exponentiation: Compute (base^exp) mod mod
 * Uses square-and-multiply algorithm
 * Time Complexity: O(log exp)
 */
long long mod_exp(long long base, long long exp, long long mod) {
    long long result = 1;
    long long x = base % mod;

    while (exp > 0) {
        // If exp is odd, multiply result with x
        if (exp % 2 == 1) {
            result = (result * x) % mod;
        }
        // Square x
        exp = exp / 2;
        x = (x * x) % mod;
    }

    return result;
}

/*
 * Generate a random private key in range [1, p-2]
 */
long long generate_private_key(long long p) {
    return (rand() % (p - 2)) + 1;
}

/*
 * Generate Diffie-Hellman key pair
 * Returns public key = g^private mod p
 */
void generate_key_pair(long long p, long long g, long long *private_key, 
                       long long *public_key) {
    *private_key = generate_private_key(p);
    *public_key = mod_exp(g, *private_key, p);
}

/*
 * Compute shared secret: S = others_public^my_private mod p
 */
long long compute_shared_secret(long long others_public, long long my_private, 
                                 long long p) {
    return mod_exp(others_public, my_private, p);
}

/*
 * Demonstrate DH with the textbook example
 */
void demonstrate_textbook_example() {
    printf("============================================================\n");
    printf("DIFFIE-HELLMAN KEY EXCHANGE - TEXTBOOK EXAMPLE (p=23)\n");
    printf("============================================================\n\n");

    // Public parameters
    long long p = 23;  // Prime number
    long long g = 5;   // Generator

    printf("Public Parameters:\n");
    printf("  Prime (p) = %lld\n", p);
    printf("  Generator (g) = %lld\n\n", g);

    // Alice's keys (using given values from textbook)
    long long a = 6;   // Alice's private key
    long long A = mod_exp(g, a, p);  // Alice's public key

    printf("Alice:\n");
    printf("  Private key (a) = %lld\n", a);
    printf("  Public key (A = g^a mod p) = %lld^%lld mod %lld = %lld\n", 
           g, a, p, A);

    // Bob's keys (using given values from textbook)
    long long b = 15;  // Bob's private key
    long long B = mod_exp(g, b, p);  // Bob's public key

    printf("\nBob:\n");
    printf("  Private key (b) = %lld\n", b);
    printf("  Public key (B = g^b mod p) = %lld^%lld mod %lld = %lld\n", 
           g, b, p, B);

    // Exchange and compute shared secrets
    long long shared_alice = compute_shared_secret(B, a, p);
    long long shared_bob = compute_shared_secret(A, b, p);

    printf("\nKey Exchange:\n");
    printf("  Alice computes: S = B^a mod p = %lld^%lld mod %lld = %lld\n", 
           B, a, p, shared_alice);
    printf("  Bob computes:   S = A^b mod p = %lld^%lld mod %lld = %lld\n", 
           A, b, p, shared_bob);

    printf("\n============================================================\n");
    if (shared_alice == shared_bob) {
        printf("SUCCESS! Shared Secret Key = %lld\n", shared_alice);
    } else {
        printf("FAILED! Keys do not match.\n");
    }
    printf("============================================================\n");
}

/*
 * Demonstrate DH with random private keys
 */
void demonstrate_random_keys() {
    printf("\n============================================================\n");
    printf("DIFFIE-HELLMAN KEY EXCHANGE - RANDOM PRIVATE KEYS\n");
    printf("============================================================\n\n");

    long long p = 23;
    long long g = 5;

    // Seed random number generator
    srand(time(NULL));

    printf("Public Parameters: p = %lld, g = %lld\n\n", p, g);

    // Generate Alice's key pair
    long long a, A;
    generate_key_pair(p, g, &a, &A);
    printf("Alice: private = %lld, public = %lld\n", a, A);

    // Generate Bob's key pair
    long long b, B;
    generate_key_pair(p, g, &b, &B);
    printf("Bob:   private = %lld, public = %lld\n", b, B);

    // Compute shared secrets
    long long shared_alice = compute_shared_secret(B, a, p);
    long long shared_bob = compute_shared_secret(A, b, p);

    printf("\nShared Secret: Alice = %lld, Bob = %lld\n", 
           shared_alice, shared_bob);

    if (shared_alice == shared_bob) {
        printf("SUCCESS! Key exchange verified.\n");
    } else {
        printf("FAILED! Keys do not match.\n");
    }

    printf("============================================================\n");
}

/*
 * Demonstrate what an eavesdropper can compute
 */
void demonstrate_eavesdropper() {
    printf("\n============================================================\n");
    printf("SECURITY DEMONSTRATION - EAVESDROPPER'S VIEW\n");
    printf("============================================================\n\n");

    long long p = 23;
    long long g = 5;
    long long a = 6;
    long long b = 15;

    long long A = mod_exp(g, a, p);
    long long B = mod_exp(g, b, p);

    printf("Eve (eavesdropper) intercepts over public channel:\n");
    printf("  p = %lld\n", p);
    printf("  g = %lld\n", g);
    printf("  Alice's public key (A) = %lld\n", A);
    printf("  Bob's public key (B) = %lld\n", B);

    printf("\nWhat Eve CAN compute:\n");
    printf("  - A = g^a mod p = %lld^%lld mod %lld = %lld [OK]\n", g, a, p, A);
    printf("  - B = g^b mod p = %lld^%lld mod %lld = %lld [OK]\n", g, b, p, B);

    printf("\nWhat Eve CANNOT compute (without solving DLP):\n");
    printf("  - Alice's private key (a) = ?\n");
    printf("  - Bob's private key (b) = ?\n");
    printf("  - Shared secret S = g^(ab) mod p\n");

    printf("\nDiscrete Logarithm Problem:\n");
    printf("  Given: g=%lld, p=%lld, A=%lld\n", g, p, A);
    printf("  Find: a such that g^a ≡ A (mod p)\n");
    printf("  For large p (2048 bits), this is computationally infeasible!\n");

    printf("============================================================\n");
}

int main() {
    demonstrate_textbook_example();
    demonstrate_random_keys();
    demonstrate_eavesdropper();

    return 0;
}

import java.math.BigInteger;
import java.security.SecureRandom;

/**
 * Diffie-Hellman Key Exchange Implementation in Java
 * Uses BigInteger for handling large prime numbers (2048-bit in practice)
 * 
 * This implementation demonstrates:
 * 1. Modular exponentiation using BigInteger's built-in method
 * 2. Generation of cryptographically secure random private keys
 * 3. The complete DH protocol with both parties reaching the same secret
 */
public class DiffieHellmanKeyExchange {

    // Public parameters (in practice, these would be 2048-bit or larger)
    private final BigInteger primeP;
    private final BigInteger generatorG;

    // Private and public keys
    private BigInteger privateKey;
    private BigInteger publicKey;
    private BigInteger sharedSecret;

    /**
     * Constructor with custom prime and generator
     */
    public DiffieHellmanKeyExchange(BigInteger p, BigInteger g) {
        this.primeP = p;
        this.generatorG = g;
        this.privateKey = null;
        this.publicKey = null;
        this.sharedSecret = null;
    }

    /**
     * Generate DH key pair using secure random number generator
     */
    public void generateKeyPair() {
        SecureRandom random = new SecureRandom();

        // Generate random private key in range [2, p-2]
        // Using BigInteger with bit length to ensure it's large enough
        int bitLength = primeP.bitLength() - 1;
        privateKey = new BigInteger(bitLength, random);

        // Ensure private key is in valid range
        privateKey = privateKey.mod(primeP.subtract(BigInteger.TWO)).add(BigInteger.TWO);

        // Compute public key: g^a mod p
        publicKey = generatorG.modPow(privateKey, primeP);
    }

    /**
     * Compute shared secret using another party's public key
     * S = (otherPublicKey)^privateKey mod p
     */
    public void computeSharedSecret(BigInteger otherPublicKey) {
        if (privateKey == null) {
            throw new IllegalStateException("Key pair not generated yet!");
        }
        sharedSecret = otherPublicKey.modPow(privateKey, primeP);
    }

    /**
     * Get the public key to share with the other party
     */
    public BigInteger getPublicKey() {
        return publicKey;
    }

    /**
     * Get the shared secret
     */
    public BigInteger getSharedSecret() {
        return sharedSecret;
    }

    /**
     * Manual modular exponentiation (educational purposes)
     * Shows how square-and-multiply works
     */
    public static BigInteger modExp(BigInteger base, BigInteger exp, BigInteger mod) {
        BigInteger result = BigInteger.ONE;
        BigInteger x = base.mod(mod);
        BigInteger e = exp;

        while (e.compareTo(BigInteger.ZERO) > 0) {
            // If exponent is odd, multiply result by x
            if (e.mod(BigInteger.TWO).equals(BigInteger.ONE)) {
                result = result.multiply(x).mod(mod);
            }
            // Square x
            e = e.divide(BigInteger.TWO);
            x = x.multiply(x).mod(mod);
        }

        return result;
    }

    /**
     * Demonstrate DH with small example (textbook example)
     */
    public static void demonstrateSmallExample() {
        System.out.println("====================================================================");
        System.out.println("DIFFIE-HELLMAN - TEXTBOOK EXAMPLE (p=23, g=5)");
        System.out.println("====================================================================\n");

        // Public parameters from textbook
        BigInteger p = new BigInteger("23");
        BigInteger g = new BigInteger("5");

        System.out.println("Public Parameters:");
        System.out.println("  Prime (p) = " + p);
        System.out.println("  Generator (g) = " + g + "\n");

        // Alice's keys (using given values)
        BigInteger a = new BigInteger("6");  // Alice's private key
        BigInteger A = g.modPow(a, p);         // Alice's public key

        System.out.println("Alice:");
        System.out.println("  Private key (a) = " + a);
        System.out.println("  Public key (A = g^a mod p) = " + A);

        // Bob's keys (using given values)
        BigInteger b = new BigInteger("15");  // Bob's private key
        BigInteger B = g.modPow(b, p);         // Bob's public key

        System.out.println("\nBob:");
        System.out.println("  Private key (b) = " + b);
        System.out.println("  Public key (B = g^b mod p) = " + B);

        // Compute shared secrets
        BigInteger aliceSecret = B.modPow(a, p);
        BigInteger bobSecret = A.modPow(b, p);

        System.out.println("\nKey Exchange:");
        System.out.println("  Alice computes: S = B^a mod p = " + aliceSecret);
        System.out.println("  Bob computes:   S = A^b mod p = " + bobSecret);

        System.out.println("\n====================================================================");
        if (aliceSecret.equals(bobSecret)) {
            System.out.println("SUCCESS! Shared Secret Key = " + aliceSecret);
        } else {
            System.out.println("FAILED!");
        }
        System.out.println("====================================================================");
    }

    /**
     * Demonstrate DH with random keys (simulating real-world use)
     */
    public static void demonstrateRandomExample() {
        System.out.println("\n====================================================================");
        System.out.println("DIFFIE-HELLMAN - RANDOM KEYS DEMONSTRATION");
        System.out.println("====================================================================\n");

        // Use a larger prime for demonstration
        BigInteger p = new BigInteger("23");
        BigInteger g = new BigInteger("5");

        System.out.println("Public Parameters: p = " + p + ", g = " + g + "\n");

        // Create Alice and Bob
        DiffieHellmanKeyExchange alice = new DiffieHellmanKeyExchange(p, g);
        DiffieHellmanKeyExchange bob = new DiffieHellmanKeyExchange(p, g);

        // Generate key pairs
        alice.generateKeyPair();
        bob.generateKeyPair();

        System.out.println("Alice: private = " + alice.privateKey + ", public = " + alice.publicKey);
        System.out.println("Bob:   private = " + bob.privateKey + ", public = " + bob.publicKey);

        // Exchange public keys and compute shared secrets
        alice.computeSharedSecret(bob.getPublicKey());
        bob.computeSharedSecret(alice.getPublicKey());

        System.out.println("\nShared Secret: Alice = " + alice.getSharedSecret() + 
                           ", Bob = " + bob.getSharedSecret());

        if (alice.getSharedSecret().equals(bob.getSharedSecret())) {
            System.out.println("SUCCESS! Both parties have the same shared secret!\n");
        }

        System.out.println("====================================================================");
    }

    /**
     * Show practical example with larger numbers
     */
    public static void demonstrateLargeNumbers() {
        System.out.println("\n====================================================================");
        System.out.println("DIFFIE-HELLMAN - LARGER NUMBERS DEMONSTRATION");
        System.out.println("====================================================================\n");

        // Using a 64-bit prime (much smaller than real 2048-bit, but larger than example)
        BigInteger p = new BigInteger("9999999967");  // Large prime
        BigInteger g = new BigInteger("5");

        System.out.println("Using larger prime p = " + p);
        System.out.println("  p bit length: " + p.bitLength() + " bits\n");

        // Create and generate key pairs
        DiffieHellmanKeyExchange alice = new DiffieHellmanKeyExchange(p, g);
        DiffieHellmanKeyExchange bob = new DiffieHellmanKeyExchange(p, g);

        alice.generateKeyPair();
        bob.generateKeyPair();

        System.out.println("Alice's public key: " + alice.getPublicKey());
        System.out.println("Bob's public key:   " + bob.getPublicKey());

        // Exchange and compute shared secrets
        alice.computeSharedSecret(bob.getPublicKey());
        bob.computeSharedSecret(alice.getPublicKey());

        System.out.println("\nShared secret computed successfully!");
        System.out.println("Both secrets match: " + alice.getSharedSecret().equals(bob.getSharedSecret()));

        System.out.println("\nIn real-world applications, p would be 2048 bits (approx 617 digits)");
        System.out.println("making it computationally infeasible to break via brute force.");
        System.out.println("====================================================================");
    }

    public static void main(String[] args) {
        demonstrateSmallExample();
        demonstrateRandomExample();
        demonstrateLargeNumbers();
    }
}
